import type { NextConfig } from "next";

const nextConfig: NextConfig = {};

export default nextConfig;

import { cacheTag } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  content: string;
  createdAt: string;
};

const posts: Post[] = [
  {
    id: 'welcome',
    title: 'Welcome to the post feed',
    content: 'This list is cached with the posts tag.'
    ,
    createdAt: new Date('2026-07-10T00:00:00.000Z').toISOString()
  }
];

export async function getPosts() {
  'use cache';

  cacheTag('posts');

  return posts.slice().sort((a, b) => b.createdAt.localeCompare(a.createdAt));
}

export function createPostRecord(title: string, content: string) {
  const post: Post = {
    id: crypto.randomUUID(),
    title,
    content,
    createdAt: new Date().toISOString()
  };

  posts.unshift(post);

  return post;
}

'use server';

import { redirect } from 'next/navigation';
import { updateTag } from 'next/cache';
import { createPostRecord } from './posts';

export async function createPost(formData: FormData) {
  const title = String(formData.get('title') ?? '').trim();
  const content = String(formData.get('content') ?? '').trim();

  if (!title || !content) {
    throw new Error('Title and content are required.');
  }

  createPostRecord(title, content);
  updateTag('posts');

  redirect('/');
}

import { createPost } from './actions';
import { getPosts } from './posts';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main style={{ maxWidth: '720px', margin: '40px auto', padding: '0 24px', fontFamily: 'system-ui, sans-serif' }}>
      <h1>Posts</h1>
      <form action={createPost} style={{ display: 'grid', gap: '12px', marginBottom: '32px' }}>
        <input name="title" placeholder="Title" required style={{ padding: '12px', fontSize: '16px' }} />
        <textarea name="content" placeholder="Content" required rows={5} style={{ padding: '12px', fontSize: '16px' }} />
        <button type="submit" style={{ width: 'fit-content', padding: '10px 16px' }}>
          Create post
        </button>
      </form>

      <section style={{ display: 'grid', gap: '16px' }}>
        {posts.map((post) => (
          <article key={post.id} style={{ border: '1px solid #ddd', borderRadius: '12px', padding: '16px' }}>
            <h2 style={{ marginTop: 0 }}>{post.title}</h2>
            <p>{post.content}</p>
            <small>{new Date(post.createdAt).toLocaleString()}</small>
          </article>
        ))}
      </section>
    </main>
  );
}

import type { NextConfig } from "next";

const nextConfig: NextConfig = {
  cacheComponents: true
};

export default nextConfig;

